import { ASSET_METADATA } from "./constants.js";
import type { StellarAsset } from "./types.js";

// ── Amount conversion ────────────────────────────────────────────────────────

/**
 * Convert a human-readable amount string to base units (integer string).
 *
 * @example toBaseUnits("0.01", "USDC") // "100000"  (7 decimals)
 * @example toBaseUnits("1", "XLM")     // "10000000" (7 decimals = stroops)
 */
export function toBaseUnits(amount: string, asset: StellarAsset): string {
  const decimals = ASSET_METADATA[asset].decimals;
  const factor = BigInt(10 ** decimals);

  // Split on decimal point
  const [intPart, fracPart = ""] = amount.split(".");
  const paddedFrac = fracPart.padEnd(decimals, "0").slice(0, decimals);

  const baseUnits =
    BigInt(intPart) * factor + BigInt(paddedFrac || "0");

  return baseUnits.toString();
}

/**
 * Convert base units (integer string) back to a human-readable amount.
 *
 * @example fromBaseUnits("100000", "USDC") // "0.0100000"
 * @example fromBaseUnits("10000000", "XLM") // "1.0000000"
 */
export function fromBaseUnits(baseUnits: string, asset: StellarAsset): string {
  const decimals = ASSET_METADATA[asset].decimals;
  const factor = BigInt(10 ** decimals);
  const value = BigInt(baseUnits);
  const intPart = value / factor;
  const fracPart = (value % factor).toString().padStart(decimals, "0");
  return `${intPart}.${fracPart}`;
}

/**
 * Convert base units string to XLM decimal string for Stellar SDK operations.
 * The SDK's Operation.payment() expects a string like "0.0100000".
 */
export function baseUnitsToXlmString(stroops: string): string {
  return fromBaseUnits(stroops, "XLM");
}

// ── Base64 encode/decode ─────────────────────────────────────────────────────

/** Encode an object to a base64 JSON string (for x402 headers). */
export function encodeHeader(obj: unknown): string {
  const json = JSON.stringify(obj);
  if (typeof Buffer !== "undefined") {
    return Buffer.from(json).toString("base64");
  }
  return btoa(json);
}

/** Decode a base64 JSON header value. */
export function decodeHeader<T>(encoded: string): T {
  let json: string;
  if (typeof Buffer !== "undefined") {
    json = Buffer.from(encoded, "base64").toString("utf-8");
  } else {
    json = atob(encoded);
  }
  return JSON.parse(json) as T;
}

// ── Safe header decode (returns null on failure) ─────────────────────────────

export function safeDecodeHeader<T>(encoded: string): T | null {
  try {
    return decodeHeader<T>(encoded);
  } catch {
    return null;
  }
}
