/**
 * x402-stellar
 *
 * Easy x402 HTTP payment protocol implementation for Stellar.
 * Supports Next.js route handlers, keypair-based agents, and Freighter browser wallets.
 *
 * @example Server (Next.js App Router)
 * ```ts
 * import { withX402 } from 'x402-stellar';
 *
 * export const GET = withX402(
 *   async (req) => Response.json({ secret: 42 }),
 *   { amount: '0.01', asset: 'USDC', network: 'testnet', payTo: 'G...' }
 * );
 * ```
 *
 * @example Client — AI agent with keypair
 * ```ts
 * import { x402Fetch } from 'x402-stellar';
 * import { Keypair } from '@stellar/stellar-sdk';
 *
 * const fetch = x402Fetch({ keypair: Keypair.fromSecret('S...'), network: 'testnet' });
 * const res = await fetch('https://api.example.com/premium');
 * ```
 *
 * @example Client — browser with Freighter
 * ```ts
 * import { x402FreighterFetch } from 'x402-stellar';
 *
 * const fetch = x402FreighterFetch({ network: 'testnet' });
 * const res = await fetch('https://api.example.com/premium');
 * ```
 */

